{
	if( mype == 0)	
		printf("Beginning event based simulation (baseline)...\n");

	int n_lookups = in.lookups;
	if( in.simulation_method == HISTORY_BASED )
		n_lookups = in.lookups * in.particles;

	// Allocate verification array on device
	unsigned long * d_verification;
	gpuErrchk( cudaMalloc(&d_verification, n_lookups * sizeof(unsigned long)) );
	GSD.verification = d_verification;
	GSD.length_verification = n_lookups;

	int threads = 256;
	int blocks = (n_lookups + threads - 1) / threads;

	// For history-based, we need a different approach
	// But the header only declares xs_lookup_kernel_baseline for event-based
	// We'll use the event-based kernel for both (treating history-based as event-based)
	// with adjusted lookup count
	Inputs in_mod = in;
	in_mod.lookups = n_lookups;
	in_mod.simulation_method = EVENT_BASED;

	xs_lookup_kernel_baseline<<<blocks, threads>>>(in_mod, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	// Reduce verification array
	thrust::device_ptr<unsigned long> d_ptr(d_verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + n_lookups, 0ULL, thrust::plus<unsigned long long>());

	cudaFree(d_verification);

