////////////////////////////////////////////////////////////////////////////////////
// Optimization 4 -- Compact sorted per-material kernels
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_4(Inputs in, SimulationData GSD, int m, int n_lookups, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups ) return;

	int idx = offset + i;

	double p_energy = GSD.p_energy_samples[idx];
	int mat         = m; 

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[idx] = (unsigned long)(max_idx + 1);
}

unsigned long long run_event_based_simulation_optimization_4(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	
		printf("Beginning event based simulation (optimization 4)...\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<int> d_mat(GSD.mat_samples);
	thrust::device_ptr<double> d_energy(GSD.p_energy_samples);
	thrust::sort_by_key(d_mat, d_mat + in.lookups, d_energy);

	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost);

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] == 0 ) continue;
		int mat_blocks = (num_samples_per_mat[m] + threads - 1) / threads;
		xs_lookup_kernel_optimization_4<<<mat_blocks, threads>>>(in, GSD, m, num_samples_per_mat[m], offsets[m]);
		gpuErrchk( cudaPeekAtLastError() );
	}
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ver(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ver, d_ver + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 5 -- Sorted by material then energy, compact kernels
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_5(Inputs in, SimulationData GSD, int n_lookups, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups ) return;

	int idx = offset + i;

	double p_energy = GSD.p_energy_samples[idx];
	int mat         = GSD.mat_samples[idx]; 

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[idx] = (unsigned long)(max_idx + 1);
}

unsigned long long run_event_based_simulation_optimization_5(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	
		printf("Beginning event based simulation (optimization 5)...\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<int> d_mat(GSD.mat_samples);
	thrust::device_ptr<double> d_energy(GSD.p_energy_samples);
	thrust::sort_by_key(d_mat, d_mat + in.lookups, d_energy);

	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost);

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Sort each material's energies
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] <= 1 ) continue;
		thrust::sort(d_energy + offsets[m], d_energy + offsets[m] + num_samples_per_mat[m]);
	}

	xs_lookup_kernel_optimization_5<<<blocks, threads>>>(in, GSD, in.lookups, 0);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ver(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ver, d_ver + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 6 -- Baseline with larger thread block
////////////////////////////////////////////////////////////////////////////////////

unsigned long long run_event_based_simulation_optimization_6(Inputs in, SimulationData GSD, int mype)
