	Inputs input;

	// defaults to the history based simulation method
	input.simulation_method = HISTORY_BASED;

	// defaults to 1 thread
	input.nthreads = 1;

	// defaults to 355 (corresponding to H-M Large benchmark)
	input.n_isotopes = 355;

	// defaults to 11303 (corresponding to H-M Large benchmark)
	input.n_gridpoints = 11303;

	// defaults to 500,000
	input.particles = 500000;

	// defaults to 34
	input.lookups = 34;

	// default to unionized grid
	input.grid_type = UNIONIZED;

	// default hash bins
	input.hash_bins = 10000;

	// default to no binary read/write
	input.binary_mode = NONE;

	// defaults to baseline kernel
	input.kernel_id = 0;

	// defaults to H-M Large benchmark
	input.HM = (char *) malloc( 6 * sizeof(char) );
	input.HM[0] = 'l' ; 
	input.HM[1] = 'a' ; 
	input.HM[2] = 'r' ; 
	input.HM[3] = 'g' ; 
	input.HM[4] = 'e' ; 
	input.HM[5] = '\0';

	// Check if user sets these
	int user_g = 0;

	int default_lookups = 1;
	int default_particles = 1;

	// Collect Raw Input
	for( int i = 1; argc > i; i++ )
	{
		char * arg = argv[i];

		// nthreads (-t)
		if( 0 == strcmp(arg, "-t") )
		{
			if( ++i < argc )
				input.nthreads = atoi(argv[i]);
			else
				print_CLI_error();
		}
		// n_gridpoints (-g)
		else if( strcmp(arg, "-g") == 0 )
		{	
			if( ++i < argc )
			{
				user_g = 1;
				input.n_gridpoints = atol(argv[i]);
			}
			else
				print_CLI_error();
		}
		// Simulation Method (-m)
		else if( 0 == strcmp(arg, "-m") )
		{
			char * sim_type;
			if( ++i < argc )
				sim_type = argv[i];
			else
				print_CLI_error();

			if( 0 == strcmp(sim_type, "history") )
				input.simulation_method = HISTORY_BASED;
			else if( 0 == strcmp(sim_type, "event") )
			{
				input.simulation_method = EVENT_BASED;
				if( default_lookups && default_particles )
				{
					input.lookups =  input.lookups * input.particles;
					input.particles = 0;
				}
			}
			else
				print_CLI_error();
		}
		// lookups (-l)
		else if( strcmp(arg, "-l") == 0 )
		{
			if( ++i < argc )
			{
				input.lookups = atoi(argv[i]);
				default_lookups = 0;
			}
			else
				print_CLI_error();
		}
		// hash bins (-h)
		else if( 0 == strcmp(arg, "-h") )
		{
			if( ++i < argc )
				input.hash_bins = atoi(argv[i]);
			else
				print_CLI_error();
		}
		// particles (-p)
		else if( strcmp(arg, "-p") == 0 )
		{
			if( ++i < argc )
			{
				input.particles = atoi(argv[i]);
				default_particles = 0;
			}
			else
				print_CLI_error();
		}
		// HM (-s)
		else if( 0 == strcmp(arg, "-s") )
		{	
			if( ++i < argc )
				input.HM = argv[i];
			else
				print_CLI_error();
		}
		// grid type (-G)
		else if( 0 == strcmp(arg, "-G") )
		{
			char * grid_type;
			if( ++i < argc )
				grid_type = argv[i];
			else
				print_CLI_error();

			if( strcmp(grid_type, "unionized") == 0 )
				input.grid_type = UNIONIZED;
			else if( strcmp(grid_type, "nuclide") == 0 )
				input.grid_type = NUCLIDE;
			else if( strcmp(grid_type, "hash") == 0 )
				input.grid_type = HASH;
			else
				print_CLI_error();
		}
		// binary mode (-b)
		else if( strcmp(arg, "-b") == 0 )
		{
			char * binary_mode;
			if( ++i < argc )
				binary_mode = argv[i];
			else
				print_CLI_error();

			if( 0 == strcmp(binary_mode, "read") )
				input.binary_mode = READ;
			else if( 0 == strcmp(binary_mode, "write") )
				input.binary_mode = WRITE;
			else
				print_CLI_error();
		}
		// kernel optimization selection (-k)
		else if( strcmp(arg, "-k") == 0 )
		{
			if( ++i < argc )
			{
				input.kernel_id = atoi(argv[i]);
			}
			else
				print_CLI_error();
		}
		else
			print_CLI_error();
	}

	// Validate Input
	if( 1 > input.nthreads )
		print_CLI_error();

	if( 1 > input.n_isotopes )
		print_CLI_error();

	if( 1 > input.n_gridpoints )
		print_CLI_error();

	if( 1 > input.lookups )
		print_CLI_error();

	if( input.hash_bins < 1 )
		print_CLI_error();

	if( strcasecmp(input.HM, "small") != 0 &&
		strcasecmp(input.HM, "large") != 0 &&
		strcasecmp(input.HM, "XL") != 0 &&
		strcasecmp(input.HM, "XXL") != 0 )
		print_CLI_error();

	if( strcasecmp(input.HM, "small") == 0 )
		input.n_isotopes = 68;
	else if( strcasecmp(input.HM, "XL") == 0 && 0 == user_g )
		input.n_gridpoints = 238847;
	else if( strcasecmp(input.HM, "XXL") == 0 && 0 == user_g )
		input.n_gridpoints = (long)(238847 * 2.1);

	return input;
}

