			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[i] = (unsigned long)(max_idx+1);
}

unsigned long long run_event_based_simulation_optimization_3(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	printf("Simulation Kernel: \"Optimization 3 - Sorted + per-material kernel launches\"\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	// Sample
	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	// Sort by material
	thrust::device_ptr<int> mat_ptr(GSD.mat_samples);
	thrust::device_ptr<double> energy_ptr(GSD.p_energy_samples);
	thrust::sort_by_key(mat_ptr, mat_ptr + in.lookups, energy_ptr);

	// Launch per-material kernels
	for( int m = 0; m < 12; m++ )
	{
		xs_lookup_kernel_optimization_3<<<blocks, threads>>>(in, GSD, m);
		gpuErrchk( cudaPeekAtLastError() );
	}
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ptr(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 4 - Sorted, per-material with offset/count
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_4(Inputs in, SimulationData GSD, int m, int n_lookups, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups ) return;

	int global_i = offset + i;

	double p_energy = GSD.p_energy_samples[global_i];
	int mat         = m; 

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[global_i] = (unsigned long)(max_idx+1);
}

unsigned long long run_event_based_simulation_optimization_4(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	printf("Simulation Kernel: \"Optimization 4 - Sorted + per-material with offsets\"\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	// Sample
	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	// Sort by material then energy
	thrust::device_ptr<int> mat_ptr(GSD.mat_samples);
	thrust::device_ptr<double> energy_ptr(GSD.p_energy_samples);
	thrust::sort_by_key(mat_ptr, mat_ptr + in.lookups, energy_ptr);

	// Count samples per material
	// Copy mat_samples to host to count
	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	gpuErrchk( cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost) );

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Launch per-material kernels with exact offsets
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] == 0 ) continue;
		int mat_blocks = (num_samples_per_mat[m] + threads - 1) / threads;
		xs_lookup_kernel_optimization_4<<<mat_blocks, threads>>>(in, GSD, m, num_samples_per_mat[m], offsets[m]);
		gpuErrchk( cudaPeekAtLastError() );
	}
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ptr(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 5 - Sorted by material+energy with offsets
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_5(Inputs in, SimulationData GSD, int n_lookups, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups ) return;

	int global_i = offset + i;

	double p_energy = GSD.p_energy_samples[global_i];
	int mat         = GSD.mat_samples[global_i]; 

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; j < 5; j++ )
	{
		if( macro_xs_vector[j] > max )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[global_i] = (unsigned long)(max_idx+1);
}

unsigned long long run_event_based_simulation_optimization_5(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	printf("Simulation Kernel: \"Optimization 5 - Sorted by material+energy with offsets\"\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	// Sample
	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	// Sort by material
	thrust::device_ptr<int> mat_ptr(GSD.mat_samples);
	thrust::device_ptr<double> energy_ptr(GSD.p_energy_samples);
	thrust::sort_by_key(mat_ptr, mat_ptr + in.lookups, energy_ptr);

	// Count samples per material
	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	gpuErrchk( cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost) );

	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Sort each material's energies
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] <= 1 ) continue;
		thrust::device_ptr<double> e_ptr(GSD.p_energy_samples + offsets[m]);
		thrust::device_ptr<int> m_ptr(GSD.mat_samples + offsets[m]);
		thrust::sort_by_key(e_ptr, e_ptr + num_samples_per_mat[m], m_ptr);
	}

	// Launch per-material kernels
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] == 0 ) continue;
		int mat_blocks = (num_samples_per_mat[m] + threads - 1) / threads;
		xs_lookup_kernel_optimization_5<<<mat_blocks, threads>>>(in, GSD, num_samples_per_mat[m], offsets[m]);
		gpuErrchk( cudaPeekAtLastError() );
	}
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ptr(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 6 - Same as baseline but with different thread configuration
////////////////////////////////////////////////////////////////////////////////////

unsigned long long run_event_based_simulation_optimization_6(Inputs in, SimulationData GSD, int mype)
{
	if( mype == 0)	printf("Simulation Kernel: \"Optimization 6 - Tuned thread configuration\"\n");

	int threads = 512;
	int blocks = (in.lookups + threads - 1) / threads;

	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk( cudaPeekAtLastError() );
	gpuErrchk( cudaDeviceSynchronize() );

	thrust::device_ptr<unsigned long> d_ptr(GSD.verification);
	unsigned long long verification = thrust::reduce(d_ptr, d_ptr + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

