	thrust::sort_by_key(d_mat, d_mat + in.lookups, d_energy);

	// Copy mat_samples to host to count per-material
	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	gpuErrchk(cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost));

	// Count samples per material and compute offsets
	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Sort each material's energies
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 0 )
		{
			thrust::device_ptr<double> d_e_offset(GSD.p_energy_samples + offsets[m]);
			thrust::sort(d_e_offset, d_e_offset + num_samples_per_mat[m]);
		}
	}

	// Launch per-material kernels with offset
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 0 )
		{
			int mat_grid = (num_samples_per_mat[m] + blockSize - 1) / blockSize;
			xs_lookup_kernel_optimization_4<<<mat_grid, blockSize>>>(in, GSD, m, num_samples_per_mat[m], offsets[m]);
			gpuErrchk(cudaPeekAtLastError());
		}
	}
	gpuErrchk(cudaDeviceSynchronize());

	// Reduce verification array
	thrust::device_ptr<unsigned long> d_verification(GSD.verification);
	unsigned long long verification = thrust::reduce(d_verification, d_verification + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

////////////////////////////////////////////////////////////////////////////////////
// Optimization 5 -- All lookups in one kernel with pre-sorted data
////////////////////////////////////////////////////////////////////////////////////

__global__ void xs_lookup_kernel_optimization_5(Inputs in, SimulationData GSD, int n_lookups, int offset )
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if( i >= n_lookups ) return;

	int global_i = offset + i;

	double p_energy = GSD.p_energy_samples[global_i];
	int mat         = GSD.mat_samples[global_i];

	double macro_xs_vector[5] = {0};

	calculate_macro_xs(
			p_energy,
			mat,
			in.n_isotopes,
			in.n_gridpoints,
			GSD.num_nucs,
			GSD.concs,
			GSD.unionized_energy_array,
			GSD.index_grid,
			GSD.nuclide_grid,
			GSD.mats,
			macro_xs_vector,
			in.grid_type,
			in.hash_bins,
			GSD.max_num_nucs
			);

	double max = -1.0;
	int max_idx = 0;
	for(int j = 0; 5 > j; j++ )
	{
		if( max < macro_xs_vector[j] )
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}
	GSD.verification[global_i] = (unsigned long)(max_idx+1);
}

unsigned long long run_event_based_simulation_optimization_5(Inputs in, SimulationData GSD, int mype)
{
	if( 0 == mype)	
		printf("Simulation Kernel: \"Optimization 5 - Sort by material+energy, single kernel\"\n");

	int blockSize = 256;
	int gridSize = (in.lookups + blockSize - 1) / blockSize;

	// Sample energies and materials
	sampling_kernel<<<gridSize, blockSize>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	// Sort by material
	thrust::device_ptr<int> d_mat(GSD.mat_samples);
	thrust::device_ptr<double> d_energy(GSD.p_energy_samples);
	thrust::sort_by_key(d_mat, d_mat + in.lookups, d_energy);

	// Copy mat_samples to host to count per-material
	int * h_mat_samples = (int *) malloc(in.lookups * sizeof(int));
	gpuErrchk(cudaMemcpy(h_mat_samples, GSD.mat_samples, in.lookups * sizeof(int), cudaMemcpyDeviceToHost));

	// Count samples per material and compute offsets
	int num_samples_per_mat[12] = {0};
	for( int l = 0; l < in.lookups; l++ )
		num_samples_per_mat[ h_mat_samples[l] ]++;

	int offsets[12] = {0};
	for( int m = 1; m < 12; m++ )
		offsets[m] = offsets[m-1] + num_samples_per_mat[m-1];

	free(h_mat_samples);

	// Sort each material's energies
	for( int m = 0; m < 12; m++ )
	{
		if( num_samples_per_mat[m] > 0 )
		{
			thrust::device_ptr<double> d_e_offset(GSD.p_energy_samples + offsets[m]);
			thrust::sort(d_e_offset, d_e_offset + num_samples_per_mat[m]);
		}
	}

	// Launch single kernel for all lookups
	xs_lookup_kernel_optimization_5<<<gridSize, blockSize>>>(in, GSD, in.lookups, 0);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	// Reduce verification array
	thrust::device_ptr<unsigned long> d_verification(GSD.verification);
	unsigned long long verification = thrust::reduce(d_verification, d_verification + in.lookups, 0ULL, thrust::plus<unsigned long long>());

	return verification;
}

